import{_ as l,c as i,o as n,a1 as s}from"./chunks/framework.DILC4Csi.js";const k=JSON.parse('{"title":"Schnellstart: Erste Schritte mit OpenSkills | OpenSkills","description":"Lernen Sie die Schnellstart-Methoden für OpenSkills. Installieren Sie Tools und Skills in 15 Minuten und ermöglichen Sie KI-Agenten, neue Skills zu nutzen und ihre Funktionsweise zu verstehen.","frontmatter":{"title":"Schnellstart: Erste Schritte mit OpenSkills | OpenSkills","sidebarTitle":"15-Minuten-Schnellstart","subtitle":"Schnellstart: Erste Schritte mit OpenSkills | OpenSkills","description":"Lernen Sie die Schnellstart-Methoden für OpenSkills. Installieren Sie Tools und Skills in 15 Minuten und ermöglichen Sie KI-Agenten, neue Skills zu nutzen und ihre Funktionsweise zu verstehen.","order":1},"headers":[],"relativePath":"de/numman-ali/openskills/start/index.md","filePath":"de/numman-ali/openskills/start/index.md"}'),t={name:"de/numman-ali/openskills/start/index.md"};function a(r,e,o,h,d,u){return n(),i("div",null,[...e[0]||(e[0]=[s(`<h1 id="schnellstart" tabindex="-1">Schnellstart <a class="header-anchor" href="#schnellstart" aria-label="Permalink to &quot;Schnellstart&quot;">​</a></h1><p>In diesem Kapitel lernen Sie die ersten Schritte mit OpenSkills kennen. Von der Installation der Tools bis zur Nutzung von Skills durch KI-Agenten – alles in 10-15 Minuten.</p><h2 id="lernpfad" tabindex="-1">Lernpfad <a class="header-anchor" href="#lernpfad" aria-label="Permalink to &quot;Lernpfad&quot;">​</a></h2><p>Wir empfehlen, in folgender Reihenfolge zu lernen:</p><h3 id="_1-schnellstart" tabindex="-1">1. <a href="./quick-start/">Schnellstart</a> <a class="header-anchor" href="#_1-schnellstart" aria-label="Permalink to &quot;1. [Schnellstart](./quick-start/)&quot;">​</a></h3><p>Abschluss der Installation von Tools, Skills und Synchronisierung innerhalb von 5 Minuten – erleben Sie den Kernwert von OpenSkills.</p><ul><li>Installation der OpenSkills-Tools</li><li>Installation von Skills aus dem offiziellen Anthropic-Repository</li><li>Synchronisierung der Skills zu AGENTS.md</li><li>Verifizierung, dass KI-Agenten die Skills nutzen können</li></ul><h3 id="_2-was-ist-openskills" tabindex="-1">2. <a href="./what-is-openskills/">Was ist OpenSkills?</a> <a class="header-anchor" href="#_2-was-ist-openskills" aria-label="Permalink to &quot;2. [Was ist OpenSkills?](./what-is-openskills/)&quot;">​</a></h3><p>Verstehen Sie die Kernkonzepte und die Funktionsweise von OpenSkills.</p><ul><li>Beziehung zwischen OpenSkills und Claude Code</li><li>Einheitliches Skills-Format, progressives Laden, Multi-Agenten-Unterstützung</li><li>Wann Sie OpenSkills anstelle des eingebauten Skills-Systems verwenden sollten</li></ul><h3 id="_3-installationsanleitung" tabindex="-1">3. <a href="./installation/">Installationsanleitung</a> <a class="header-anchor" href="#_3-installationsanleitung" aria-label="Permalink to &quot;3. [Installationsanleitung](./installation/)&quot;">​</a></h3><p>Ausführliche Installationsschritte und Umgebungskonfiguration.</p><ul><li>Prüfung von Node.js und Git-Umgebung</li><li>Temporäre Nutzung vs. globale Installation</li><li>Behebung häufiger Installationsprobleme</li></ul><h3 id="_4-ersten-skill-installieren" tabindex="-1">4. <a href="./first-skill/">Ersten Skill installieren</a> <a class="header-anchor" href="#_4-ersten-skill-installieren" aria-label="Permalink to &quot;4. [Ersten Skill installieren](./first-skill/)&quot;">​</a></h3><p>Von Anthropic offiziellem Repository Skills installieren und die interaktive Auswahl erleben.</p><ul><li>Verwendung des <code>openskills install</code>-Befehls</li><li>Interaktive Auswahl der benötigten Skills</li><li>Verständnis der Verzeichnisstruktur von Skills (.claude/skills/)</li></ul><h3 id="_5-skills-zu-agents-md-synchronisieren" tabindex="-1">5. <a href="./sync-to-agents/">Skills zu AGENTS.md synchronisieren</a> <a class="header-anchor" href="#_5-skills-zu-agents-md-synchronisieren" aria-label="Permalink to &quot;5. [Skills zu AGENTS.md synchronisieren](./sync-to-agents/)&quot;">​</a></h3><p>Erstellen Sie die AGENTS.md-Datei, damit KI-Agenten verfügbare Skills erkennen.</p><ul><li>Verwendung des <code>openskills sync</code>-Befehls</li><li>Verständnis des XML-Formats von AGENTS.md</li><li>Auswahl der zu synchronisierenden Skills zur Kontrolle der Kontextgröße</li></ul><h3 id="_6-skills-verwenden" tabindex="-1">6. <a href="./read-skills/">Skills verwenden</a> <a class="header-anchor" href="#_6-skills-verwenden" aria-label="Permalink to &quot;6. [Skills verwenden](./read-skills/)&quot;">​</a></h3><p>Erfahren Sie, wie KI-Agenten Skill-Inhalte laden.</p><ul><li>Verwendung des <code>openskills read</code>-Befehls</li><li>4-stufige Prioritätsreihenfolge bei der Skill-Suche</li><li>Lesen mehrerer Skills gleichzeitig</li></ul><h2 id="voraussetzungen" tabindex="-1">Voraussetzungen <a class="header-anchor" href="#voraussetzungen" aria-label="Permalink to &quot;Voraussetzungen&quot;">​</a></h2><p>Bevor Sie beginnen, stellen Sie sicher:</p><ul><li><a href="https://nodejs.org/" target="_blank" rel="noreferrer">Node.js</a> 20.6.0 oder höher ist installiert</li><li><a href="https://git-scm.com/" target="_blank" rel="noreferrer">Git</a> ist installiert (für die Installation von Skills aus GitHub)</li><li>Mindestens ein KI-Coding-Agent ist installiert (Claude Code, Cursor, Windsurf, Aider usw.)</li></ul><div class="tip custom-block"><p class="custom-block-title">Schnelle Umgebungsprüfung</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">node</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -v</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">  # Sollte v20.6.0 oder höher anzeigen</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">git</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -v</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">   # Sollte git version x.x.x anzeigen</span></span></code></pre></div></div><h2 id="nachste-schritte" tabindex="-1">Nächste Schritte <a class="header-anchor" href="#nachste-schritte" aria-label="Permalink to &quot;Nächste Schritte&quot;">​</a></h2><p>Nach Abschluss dieses Kapitels können Sie weiter lernen:</p><ul><li><a href="./../platforms/cli-commands/">Befehle im Detail</a>: Vertiefen Sie alle Befehle und Parameter</li><li><a href="./../platforms/install-sources/">Installationsquellen im Detail</a>: Lernen Sie, Skills aus GitHub, lokalen Pfaden und privaten Repositories zu installieren</li><li><a href="./../advanced/create-skills/">Eigene Skills erstellen</a>: Erstellen Sie Ihre eigenen Skills</li></ul>`,29)])])}const p=l(t,[["render",a]]);export{k as __pageData,p as default};
